import{_ as e,o as r,c as p,a9 as a}from"./chunks/framework.D4xYp1Zt.js";const n="/images/picking-career/river-2.png",o="/images/picking-career/pond-1.png",s="/images/picking-career/Looking-at-shore-2.png",i="/images/picking-career/shore-1.jpg",g="/images/picking-career/shore-2.jpg",l="/images/picking-career/Pie-Chart.png",c="/images/picking-career/Life-path.png",m="/images/picking-career/map1.png",h="/images/picking-career/map2.png",w="/images/picking-career/map3.png",f="/images/picking-career/Want-Box.png",u="/images/picking-career/Reality-Box.png",_="/images/picking-career/venn.png",k="/images/picking-career/Octopus-1.png",b="/images/picking-career/Octopus-2a.png",d="/images/picking-career/Octopus-2B.png",y="/images/picking-career/Octopus-3-segmented-1.png",B="/images/picking-career/personal-tentacle.png",P="/images/picking-career/social-tentacle.png",W="/images/picking-career/lifestyle-tentacle.png",q="/images/picking-career/moral-tentacle-1.png",O="/images/picking-career/practical-tentacle.png",v="/images/picking-career/Passion-argument.png",A="/images/picking-career/mask-1.png",x="/images/picking-career/mask-2.png",C="/images/picking-career/mask-3.png",T="/images/picking-career/mask-4.png",E="/images/picking-career/mask-5-1.png",S="/images/picking-career/mask-6.png",H="/images/picking-career/mask-7.png",Y="/images/picking-career/mask-8-1.png",N="/images/picking-career/roller-coaster-1-2.png",R="/images/picking-career/denial-prison-1-1.png",F="/images/picking-career/denial-prison-2.png",L="/images/picking-career/yearning-hierarchy-2.png",D="/images/picking-career/octopus-no-bones-1.png",J="/images/picking-career/A-star-1-1.png",V="/images/picking-career/A-star-2-1.png",j="/images/picking-career/A-star-3-1.png",M="/images/picking-career/A-star-4-2.png",K="/images/picking-career/Chef-Strategy-Loop-1.png",Z="/images/picking-career/venn-1.png",$="/images/picking-career/roller-coaster-2-2.png",G="/images/picking-career/tunnels-2.png",I="/images/picking-career/opportunity-cost-2.png",U="/images/picking-career/inertia-spectrum.png",z="/images/picking-career/venn-with-loops-small.png",X="/images/picking-career/venn-with-big-loop-small.png",Q="/images/picking-career/pinit_fg_en_rect_gray_20.png",it=JSON.parse('{"title":"How to Pick a Career (That Actually Fits You) — Wait But Why","description":"","frontmatter":{"title":"How to Pick a Career (That Actually Fits You) — Wait But Why","titleZh":"如何选择真正适合你的职业","date":"2018-04-12T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2018/04/picking-career.html","slug":"picking-career"},"headers":[],"relativePath":"posts/picking-career.md","filePath":"posts/picking-career.md","lastUpdated":1782886257000}'),tt={name:"posts/picking-career.md"};function et(rt,t,pt,at,nt,ot){return r(),p("div",null,[...t[0]||(t[0]=[a('<h1 id="如何选择真正适合你的职业-·-how-to-pick-a-career-that-actually-fits-you-—-wait-but-why" tabindex="-1">如何选择真正适合你的职业 · How to Pick a Career (That Actually Fits You) — Wait But Why <a class="header-anchor" href="#如何选择真正适合你的职业-·-how-to-pick-a-career-that-actually-fits-you-—-wait-but-why" aria-label="Permalink to &quot;如何选择真正适合你的职业 · How to Pick a Career (That Actually Fits You) — Wait But Why&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2018/04/picking-career.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2018/04/picking-career.html</a> · 2018-04-12</p></blockquote><p>读者们好!正式开始之前先说几句:</p><p>这篇文章讲的是一件我一直想写的事:职业。社会告诉我们一大堆关于职业的东西——我们应该想要什么、可能性有哪些——但奇怪的是,我几乎可以肯定社会对这些几乎一无所知。一说到职业,社会就像你那位过节时把你堵在角落里、滔滔不绝讲 15 分钟基本前言不搭后语的强塞式建议独白的舅公,而你几乎全程神游,因为一听就知道他自己都不太清楚自己在说什么,而且他说的每句话都像是过时了 45 年。社会就像那位舅公,而所谓「常识」就像他的那通唠叨。只不过在职业这件事上,我们不但没有神游,反而聚精会神听他说的每一个字,然后据此做出人生的重大职业决定。也是挺奇怪的一件事。</p><p>这篇文章其实不是我在给你职业建议——它是一个思考框架,我觉得可以帮你做出真正反映你是谁、你想要什么、以及当今这个飞速变化的职业世界的现状的职业决定。这方面你不是专家,但你肯定比我们那位集体无自知之明的舅公更有资格搞清楚什么对你最好。对于那些还没开始职业生涯、不确定自己想做什么的人,或者正处在职业中期、不确定自己走对了路的人,希望这篇文章能帮你按下思路的重置键,获得一些清晰感。</p><p>– Tim</p><h2 id="pdf-版-如果你想打印这篇文章或离线阅读-pdf-版可能是最好的选择。点这里购买。" tabindex="-1"><em><strong>PDF 版:</strong> 如果你想打印这篇文章或离线阅读,PDF 版可能是最好的选择。<a href="https://gum.co/wbw-career-path" target="_blank" rel="noreferrer">点这里购买</a>。</em> <a class="header-anchor" href="#pdf-版-如果你想打印这篇文章或离线阅读-pdf-版可能是最好的选择。点这里购买。" aria-label="Permalink to &quot;***PDF 版:** 如果你想打印这篇文章或离线阅读,PDF 版可能是最好的选择。[点这里购买](https://gum.co/wbw-career-path)。*&quot;">​</a></h2><h5 id="你目前为止的人生轨迹" tabindex="-1"><strong>你目前为止的人生轨迹</strong> <a class="header-anchor" href="#你目前为止的人生轨迹" aria-label="Permalink to &quot;**你目前为止的人生轨迹**&quot;">​</a></h5><p>对我们大多数人来说,童年有点像一条河,而我们有点像蝌蚪。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/river-2.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt=""></a></p><p>我们没有选择这条河。我们只是不知道从哪儿冒出来醒过来,发现自己身处一条由父母、社会和环境为我们设定好的路径上。别人告诉我们河的规则、我们该怎么游、目标应该是什么。我们的任务不是思考自己的路径——而是在被安置的这条路径上取得成功,基于别人为我们定义好的成功标准。</p><p>对我们中的许多人来说——我猜对 Wait But Why 的很大一部分读者来说也是如此——童年这条河接下来会汇入一个池塘,叫做大学。<a href="#footnote-1-6721">1</a> 我们对具体落进哪个池塘可能有点发言权,但归根结底,大多数大学池塘之间其实没什么本质区别。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/pond-1.png" target="_blank" rel="noreferrer"><img src="'+o+'" alt=""></a></p><p>在池塘里,我们有了稍微多一点的喘息空间,也有了一些余地去发展更具体的兴趣。我们开始沉思,望向池塘的岸边——那里是真实世界开始的地方,是我们将要度过余生的地方。这通常会带来一些复杂的情绪。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/Looking-at-shore-2.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt=""></a></p><p>然后,在湍急的河流中醒来 22 年之后,我们被踢出池塘,被这个世界告知要去闯出一番人生。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/shore-1.jpg" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a></p><p>这里有几个问题。其中之一是,在那一刻,你算是没什么技能、没什么知识,以及没什么其他很多东西:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/shore-2.jpg" target="_blank" rel="noreferrer"><img src="'+g+'" alt=""></a></p><p>但在你还来不及处理自己整体的没用之前,有一个更大的问题——你预设好的路径结束了。学校里的孩子有点像一家公司里的员工,而 CEO 是别人。但在真实世界里,没有人是你人生的 CEO,也没有人是你职业道路的 CEO——除了你自己。而你把整个人生都花在了成为一名专业学生上,这让你在担任任何东西的 CEO 方面经验为零。到目前为止,你只负责微观决策——「我怎么把学生这份工作做好?」——而现在你突然也拿到了宏观驾驶舱的钥匙,被要求回答一些让人压力山大的宏观问题,比如「我是谁?」、「人生中重要的事情是什么?」以及「我的路径都有哪些选择,我该选哪一条,我又该怎么开辟一条路?」当我们最后一次离开学校时,我们已经习惯了的宏观指导突然被从我们身边抽走,把我们孤零零地留在原地,一手抓着自己的老二,毫无头绪该怎么办。</p><p>然后时间流逝。我们最终走上了某条路。而那条路成了我们人生的故事。</p><p>在我们生命的尽头,当我们回望这一切是如何走过来的,我们可以从空中俯瞰的视角,看到自己人生道路的全貌。</p><p>当科学家研究临终之人以及他们对自己一生的感受时,他们通常会发现许多人都怀有一些严重的遗憾。我觉得这些遗憾中的很多都源于一个事实:我们大多数人在童年时并没有真正被教过如何开辟道路,而且大多数人成年后在开辟道路这件事上也没有变得多好,这就导致很多人回头看时,发现自己走过的这条路,考虑到自己是谁以及自己所处的世界,其实并不怎么讲得通。</p><p>所以这是一篇关于开辟道路的文章。让我们做一次 30 分钟的、临终前的暂停,低头看看自己正在走的这条路,以及往前看看这条路似乎要通向哪里,并确保它是讲得通的。</p><p><strong>厨子与大厨——旧话重提</strong></p><p>过去,<a href="https://waitbutwhy.com/2015/11/the-cook-and-the-chef-musks-secret-sauce.html" target="_blank" rel="noreferrer">我写过</a>「从第一性原理出发的推理」和「类比式推理」之间的关键区别——或者用我的说法,就是当「厨师 (chef)」还是当「炊事员 (cook)」的区别。写完那篇文章之后,我发现这种区分无处不在,并在自己的生活里大约想过 200 万次。</p><p>这个想法是,从第一性原理出发的推理,就像科学家那样思考。你从核心事实和观察出发,把它们像拼图一样凑成结论,有点像厨师玩弄原材料,试图把它们变成某种美味的东西。通过这种拼图过程,厨师最终写出了新菜谱。另一种推理——类比式推理——发生在你看着别人已经在做什么,然后基本上照搬过来,可能这里那里加一点点个人调整——就像炊事员照着已经写好的菜谱做菜。</p><p>一个逐字照搬菜谱的纯粹炊事员,和一个完全独立发明的纯粹厨师,是一条光谱的两个极端。但对于你生活中任何涉及推理和决策的部分,不管你在光谱上处于哪个位置,你的推理过程通常可以归结为本质上像厨师,还是本质上像炊事员。创造 vs. 复制。原创 vs. 从众。</p><p>当厨师需要花费大量的时间和精力——这是理所当然的,因为你不是在重新发明轮子,而是在第一次发明它。拼图般地推向结论,感觉就像蒙着眼睛穿越神秘森林,而且总是伴随着大量的失败,以试错的形式出现。当炊事员则要容易得多、直接得多、也没那么恶心。在大多数情况下,当厨师是一种可怕的时间浪费,机会成本极高,因为地球上的时间极其稀缺。此刻,我穿着 J. Crew 的牛仔裤、一件普通 T 恤、一件连帽衫和 Allbirds 的鞋,因为我在努力从众。在我这辈子里,我一直环顾四周,看那些看起来跟我差不多的人,然后买一堆跟他们穿的差不多的衣服。这很合理——因为衣服对我来说不重要,也不是我用来表达个性的方式。所以在我这种情况下,时尚是一个完美的适合走推理捷径、当炊事员的生活领域。<a href="#footnote-2-6721">2</a></p><p>但生活里还有一些部分真的真的极其重要——比如你选择住在哪里,你选择交什么样的朋友,你想不想结婚以及跟谁结婚,你想不想要孩子以及怎么养他们,你怎么设定你的生活方式的优先级。</p><p>规划职业道路绝对是这些真的真的极其重要的事情之一。让我们把显而易见的原因写明白:</p><p><strong>时间。</strong> 对我们大多数人来说,职业(包括附属的职业时间,比如通勤和思考工作的时间)会吃掉 5 万到 15 万小时之间的时间。目前,漫长的一生大约有 75 万小时。当你减去童年(约 17.5 万小时)以及成年后花在睡觉、吃饭、锻炼、照顾你所居住的这只人类宠物,再加上跑腿和日常生活维护的时间(约 32.5 万小时),你就只剩下 25 万个「有意义的成年小时」了。<a href="#footnote-3-6721">3</a> 所以典型的职业会占用你 20% 到 60% 之间的有意义成年时间——这可不是能糊弄的事。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/Pie-Chart.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt=""></a></p><p><strong>生活质量。</strong> 你的职业对所有非职业时间也有重大影响。对于我们这些没有靠过去的收入、婚姻或遗产已经致富的人来说,职业同时也是我们的生活来源。你职业的具体情况通常还在很大程度上决定了你住在哪里、你的生活有多灵活、你在空闲时间能做什么样的事情,有时甚至决定了你最终和谁结婚。</p><p><strong>影响力。</strong> 除了你的职业是你花费大部分时间的方式、以及你其余时间的生活来源之外,你的职业还兼具第三重身份——你产生影响的主要方式。每个人的生命都以数千种不同的方式触及数千个其他生命,而所有那些被你改变的生命又会继续触及他们自己的数千个生命。我们没法做实验验证,但我很确定,你可以随便挑一个今天在世的 80 岁老人,回到 80 年前,找到还是婴儿的他,把这个婴儿扔进垃圾桶,然后回到今天,你会发现无数事情都变了。所有人的生命都对世界和未来产生了巨大影响——但你最终产生什么<em>样</em>的影响,很大程度上取决于你自己,取决于你所秉持的价值观和你把精力投向哪里。不管你的职业道路最终是什么形状,世界都会因它而改变。</p><p><strong>身份认同。</strong> 在我们的童年,别人问我们的职业规划时,问的是我们长大后想「成为」什么。等我们长大了,我们向别人介绍自己的职业时,说的是我们「是」什么。我们不说「我从事法律工作」——我们说「我是一名律师」。这可能是一种不健康的看待职业的方式,但按照现在许多社会的样子,一个人的职业还兼具第四重身份——这个人的主要身份认同。这可是件不小的事。</p><p>所以啊——你的职业道路可不像我那件破卫衣。它真的真的极其重要,妥妥地属于「绝对必须像大厨一样对待」的范畴。</p><p><strong>你的职业地图</strong></p><p>这就说到你了。我不知道你具体是什么情况。但很有可能你正处于某个蓝色区域中的一个——</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/Life-path.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt=""></a></p><p>——也就是说,你的职业道路还在建设中。<a href="#footnote-4-6721">4</a></p><p>不管你是还没开始自己的职业生涯,还是已经深陷其中,在你脑子的某个角落里(或者干脆就摆在最前面),都有一张「职业规划」地图。</p><p>我们可以把地图的持有者大致分成三类——不管是在河里的、池塘里的、站在岸上的,还是处于成年生活任何阶段的人,这三类都很常见。</p><p>一类人看着这张地图,看到的是一个巨大的、令人焦虑的问号。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/map1.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt=""></a></p><p>这些人对自己的职业道路犹豫不决。别人告诉他们要追随激情,但他们对什么都提不起特别的激情。别人告诉他们让自己的长处来指引方向,但他们也不确定自己到底最擅长什么。他们过去或许觉得自己有答案,但人已经变了,如今再也说不清自己是谁、要去哪。</p><p>另一类人看到的是一个清晰漂亮的箭头,代表他们自信正确的方向——但他们的双腿却朝着另一个方向走。他们正过着人类最普遍的痛苦源头之一的生活:一条自己心里明明知道走错了的职业路。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/map2.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt=""></a></p><p>而幸运的那批人,觉得自己知道要去哪,并且相信自己正朝那个方向大步前进。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/map3.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt=""></a></p><p>但即便是这些人,也应该停下来问问自己:「这个箭头到底是谁画的?真的是我画的吗?」答案可能会让人有点迷糊。</p><p>我敢肯定,以上这些人都能从片刻的职业道路反思中受益。</p><p><strong>「好吧但你凭什么觉得你能帮我做职业反思你不就是靠画火柴人过活的吗」蓝框</strong></p><p>问得非常公道。每次选题的时候,我都会问自己一件事:「我有资格写这个吗?」以下是我决定接下这个题目的理由:</p><p>1)过去 20 年里,我大部分时间都处在一种对自己职业道路持续分析的状态。</p><p>2)我的路线拐了很多弯——7 岁想当电影明星,17 岁想当总统,22 岁想给电影配乐,24 岁想创业,29 岁想写音乐剧,最近则想当个「写东西的人」。</p><p>3)在人生大部分时间里,我的职业方向一直乱七八糟,但我现在其实很喜欢我的工作。这当然随时可能变化,但能够把那些把我带进迷茫或沮丧境地的决策过程,跟那些把我带向更充实境地的决策放在一起对比,让我对人们通常在哪里走岔了这件事,多少有了一些心得。</p><ol start="4"><li><p>除了我自己的故事可以研究,我还坐在最前排,近距离观察了我十几个最亲密朋友的故事。我的朋友们似乎和我一样对职业道路很执着,所以通过观察他们的路径,并在这一路上一次又一次地和他们讨论这些路径,我拓宽了自己对这个话题的看法,这帮助我区分哪些教训是专属于我个人的,哪些是更普遍适用的。</p></li><li><p>最后,这篇文章并不是关于哪些职业比哪些更好或更差,也不是关于哪些职业价值观更有意义或更没意义——外面有很多社会科学家和自助类作者在这方面有很好的数据,而我不是其中之一。这篇文章提供的是一个框架,我认为它能帮助一个正在思考职业道路的人更清晰、更诚实地看清自己的处境,以及什么对自己真正重要。这个框架对我来说非常好用,所以我觉得它对其他人可能也会有帮助。</p></li></ol><h2 id="现在-你已经重新审视了你的职业规划地图-以及上面可能有或没有的那支箭-请把它放下-收起来别看。我们会在文章最后回到它。现在是时候深入挖掘了——让我们从零开始思考这个问题。从第一性原理出发。" tabindex="-1">现在,你已经重新审视了你的职业规划地图,以及上面可能有或没有的那支箭,请把它放下,收起来别看。我们会在文章最后回到它。现在是时候深入挖掘了——让我们从零开始思考这个问题。从第一性原理出发。 <a class="header-anchor" href="#现在-你已经重新审视了你的职业规划地图-以及上面可能有或没有的那支箭-请把它放下-收起来别看。我们会在文章最后回到它。现在是时候深入挖掘了——让我们从零开始思考这个问题。从第一性原理出发。" aria-label="Permalink to &quot;现在,你已经重新审视了你的职业规划地图,以及上面可能有或没有的那支箭,请把它放下,收起来别看。我们会在文章最后回到它。现在是时候深入挖掘了——让我们从零开始思考这个问题。从第一性原理出发。&quot;">​</a></h2><p>在<a href="https://waitbutwhy.com/2015/11/the-cook-and-the-chef-musks-secret-sauce.html" target="_blank" rel="noreferrer">厨子与大厨那篇文章</a>里,我设计了一个简单的框架,来说明大厨是如何做出重大职业选择的。其核心是一个简单的文氏图。</p><p>图的第一部分是「想要盒 (Want Box)」,里面装着所有你觉得可取的职业。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/Want-Box.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt=""></a></p><p>图的第二部分是「现实盒 (Reality Box)」。现实盒装的是所有你有可能实际实现的职业——每一个都要基于你在某个领域的潜力水平与在该领域取得成功的一般难度之间的对比来判断。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/Reality-Box.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt=""></a></p><p>重叠区域包含了你最优的职业道路选择——也就是你应该考虑在职业地图上画出的那些箭头的集合。我们可以把它叫做「选项池 (Option Pool)」。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/venn.png" target="_blank" rel="noreferrer"><img src="'+_+'" alt=""></a></p><p>这个思路够简单明了了。但真要准确地填好这两个盒子,比看起来难得多。要让这个图有用,它就必须尽可能接近真相,而要做到这点,我们得掀开潜意识的引擎盖,钻进去看看。我们先从「想要盒」开始。</p><p><strong>深度分析,第一部分:你的「想要盒」</strong></p><p>「想要盒子 (Want Box)」的难点在于,你想要的东西是一大堆——或者更准确地说,你身上有一大堆不同的侧面,每一面都想要——并且害怕——它自己的那套东西。既然有些动机之间存在利益冲突,那么从定义上说,你不可能拥有你想要的一切。追求一件你想要的东西,从定义上就意味着不去追求其他的,有时候还特指要直接<em>反其道而行</em>。「想要盒子」是一场妥协的游戏。</p><p><strong>渴望章鱼 (Yearning Octopus)</strong></p><p>要做一次像样的「想要盒子」审计,你需要想清楚你在职业上渴望什么,然后把它彻底拆开来分析。幸运的是,这里有一位能帮上忙的家伙——渴望章鱼。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/Octopus-1.png" target="_blank" rel="noreferrer"><img src="'+k+'" alt=""></a></p><p>我们每个人脑子里都住着一只自己专属的渴望章鱼<a href="#footnote-5-6721">5</a>。每个人的渴望章鱼在细节上会有所不同,但人和人之间其实也没那么不同,我敢打赌我们中很多人的渴望和恐惧都非常相似(尤其考虑到我发现 Wait But Why 的读者们往往有很多共同点)。</p><p>首先要意识到的是,存在一些完全不同的渴望<em>世界</em>——每个都栖息在一条触手上。这些触手之间常常处不来。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/Octopus-2a.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt=""></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/Octopus-2B.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt=""></a></p><p>情况还会更糟。每条触手都由一堆不同的个体渴望以及与之相伴的恐惧组成——而<em>这些</em>彼此之间也经常严重打架。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/Octopus-3-segmented-1.png" target="_blank" rel="noreferrer"><img src="'+y+'" alt=""></a></p><p>我们来近距离看看每条触手上究竟在发生什么。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/personal-tentacle.png" target="_blank" rel="noreferrer"><img src="'+B+'" alt=""></a></p><p>「个人渴望」这条触手大概是这里最难泛化的一条——它对每个人来说都相当特殊。它是我们独特个性与价值观的映射,承载着大概是人类最复杂、最具挑战性的需求:自我实现。而且它还得同时应付你现在的自己以及一堆过去的自己。7 岁的你的梦想、12 岁的你所憧憬的理想身份、17 岁的你的秘密愿望、以及你当下不断演变的热情,全都挤在个人触手上的某个位置,各自为了得到自己想要的东西闹着小脾气,并且随时准备好在你辜负它们的时候,用它们的失望与嫌弃让你自我感觉糟糕透顶。此外,你对死亡的恐惧有时也会从个人触手上冒出来,黏黏糊糊地要求你留下印记、成就伟大、诸如此类。个人触手就是为什么你找不到多少亿万富翁甘愿在沙滩上啜饮鸡尾酒度过余生——它是一条极其难伺候的触手。</p><p>然而,个人触手也常常是最终多少被忽视的那一条。因为在很多情况下,它是最令人不适、最难真正<em>付诸行动</em>去追求的一组渴望;因为这条触手上的恐惧不会立刻显得可怕——它们是随着时间从背景中悄悄爬出来的;还因为在你职业生涯早期,个人触手总是有被其他触手那些强大的动物性情绪一举撞飞的风险。这种忽视可能会让一个人在尘埃落定之后带着巨大的遗憾。一个「个人渴望」触手未被满足的例子,常常就是那种非常成功、却非常不快乐的人——他们可能觉得自己是在错误的领域里成功了。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/social-tentacle.png" target="_blank" rel="noreferrer"><img src="'+P+'" alt=""></a></p><p>「社交渴望」触手大概是我们最原始、最动物性的一面,它的核心驱动力可以追溯到我们部落式的进化过去。这条触手上住着一些古怪的生物。</p><p>正如我们<a href="https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html" target="_blank" rel="noreferrer">之前</a>在这个博客上讨论过的,我们脑子里都住着一头「社交生存猛犸象 (Social Survival Mammoth)」,它对其他人怎么看我们这件事有一种惊天动地的执念。这意味着它渴望被接纳、被包容、被喜爱,同时对尴尬、负面评价和不认可怕得要死。它非常非常非常想待在圈内群体里,也非常非常非常不想待在圈外群体里。不过它<a href="https://28oa9i1t08037ue3m1l0i861-wpengine.netdna-ssl.com/wp-content/uploads/2014/06/Mammoth1.png" target="_blank" rel="noreferrer">还挺可爱的</a>。</p><p>然后是你的自尊 (ego),它和前面那个角色差不多,但更加需要被满足。你的自尊不只是想被接纳;它想被崇拜、被渴望、被讨好——最好是大规模地被讨好。比起被讨厌,它更受不了的是被忽视。它想变得有影响力、重要、广为人知。</p><p>还有其他角色在这条触手上晃悠。社交触手的某个地方有一个小法官,拿着一个小法槌,如果它觉得人们没有公正地评判你——你没有得到应有的欣赏——它就会气得不行。让别人清楚地知道你自认为有多聪明多有才华,这对法官来说非常重要。法官还特别爱记仇——这就是为什么很多人做事的最大动力,是想向那些从不相信他们的人<strong>证明</strong>点什么。</p><p>最后,我们中的一些人可能会在社交触手上发现一只可爱的小狗,它比世界上任何东西都更想取悦它的主人,一想到会让主人失望就承受不了。这只可爱小生物唯一的问题是,它的主人不是你。它的主人是一个对你有巨大心理影响力的人,如果你不小心,你可能会把整个职业生涯都奉献给取悦他们、让他们为你自豪。(这个人多半是父母。)</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/lifestyle-tentacle.png" target="_blank" rel="noreferrer"><img src="'+W+'" alt=""></a></p><p>生活方式渴求 (Lifestyle Yearnings) 这条触手基本上只希望周二是美好的一天。而且是那种真的很愉快、很享受的一天——有充足的空闲时间、自我关照、放松和小奢侈。</p><p>它也关心你整个人生的大局要尽可能美好——就生活方式触手的立场而言,你应该能在人生中做自己想做的事,以自己想要的时间和方式,和自己最喜欢的人在一起。生活应该充满有趣的时光和丰富的体验,但也应该顺畅地流动,不用太辛苦,路上尽量少些坎坷。</p><p>问题是,即便你把生活方式渴求排在很高的优先级,也很难让整条触手同时开心。触手上那个只想坐着放松的部分,会阻止你去拼命建设一个能带来长期自由、能让生活奢华舒适充满玩具的那种财富的职业。触手上那个只有在未来可预测时才觉得舒服的部分,会拒绝那些恰恰能带来另一部分触手所渴望的长期自由的道路。你身上想要无压力生活的那一面,和渴望像理查德·布兰森 (Richard Branson) 那样在纳米比亚悬崖上玩滑翔翼的那一面,合不来。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/moral-tentacle-1.png" target="_blank" rel="noreferrer"><img src="'+q+'" alt=""></a></p><p>「道德渴望 (Moral Yearnings)」这条触手觉得你「渴望章鱼」身上其他所有触手都是一群自私鬼——一个比一个自我中心、自我放纵。道德触手上的那部分你,环顾四周,看到一个亟需修补的大千世界;看到几十亿人,他们过上好日子的资格丝毫不比你差,只是不巧生在了较差的环境里;看到一个不确定的未来,地球上的生命正悬在乌托邦与反乌托邦之间摇摆——只要我们能把其他触手撇到一边,这个未来其实是可以被推向正确方向的。当其他触手都在幻想「如果我银行里有十亿美元,我这辈子要怎么过」的时候,道德触手幻想的却是「如果我有十亿美元可以<em>调配</em>,我能造成多大的影响」。</p><p>不用说,你「渴望章鱼」的其他触手都觉得道德触手实在让人无法忍受。它们也完全无法理解为慈善而慈善这种事——它们心想:「别人又不是我,我干嘛把时间和精力花在帮他们身上?」——但它们<em>能</em>理解出于自身动机的慈善。虽然道德触手和生活方式触手往往正面冲突,但道德触手有时能和其他触手找到共同点——社交触手要是发现慈善能让你赢得某个高地位社交圈的尊敬和崇拜,它就会对慈善非常上心;而某些人的个人触手可能会在慈善事业里找到它苦苦渴求的意义感或自我价值。</p><p>所以当你做慈善的时候——或者其实做任何利他行为的时候——你脑袋里同时在跑好几个不同的东西。那个<em>一定</em>要为这件善事赢得应有公众认可的部分,住在你的社交触手上;那个心想「天啊我真是个好人」的部分,住在你的个人触手上;而那个真心乐见被你帮助的人或群体过得更好的部分,则住在你的道德触手上。反过来,<em>不</em>为他人做任何事,也会在多条触手上让你难受——道德触手会感到愧疚和悲伤,社交触手会担心别人把你看成自私鬼或贪婪之徒,而个人触手可能因此拉低你的自尊。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/practical-tentacle.png" target="_blank" rel="noreferrer"><img src="'+O+'" alt=""></a></p><p>你的<strong>实用渴望触手</strong>觉得这一切都挺好挺棒的——但它也想指出,今天是 3 月 31 日,明天就要交房租了,好笑的是它刚刚登录了你的银行账户,发现里面的钱其实比你房东在接下来 34 小时里要从你这拿走的钱还要少。是的它知道你周四存了那张支票,应该明天早上到账,但你的实用触手也可以发誓,就在上个月,所有触手都答应过要做点牺牲、至少攒出一点点银行账户余额缓冲,这样每个月交房租就不用真他妈那么焦虑。你的实用触手还忍不住注意到,你的<strong>社交触手</strong>上周六在酒吧主动请了同去的九个人一轮酒,就为了让那些人觉得你是个有品位、大方的人;你的<strong>生活方式触手</strong>给一个现在月光的人选了一套看起来相当不错的公寓来租;还有那位你朋友六个月前开的百吉饼外卖服务——你的<strong>道德触手</strong>很开心地投了 2,500 美元帮他起步——最近关于它的更新变得非常安静;哦对了,与此同时你的<strong>个人触手</strong>让所有人在两个喜剧写作的实习岗位上同时累到吐血,而这两份工加起来赚的钱,居然还不如你大二在 Jekyll &amp; Hyde 装扮成埃及女巫当服务员挣得多。</p><p>在最基本的层面上,你的实用触手只是想确保你能吃上饭、穿上衣服、买得起需要的药、不用露宿街头。它其实并不在乎这些事情是怎么实现的——它只想它们被实现。但章鱼身上的其他所有触手都在瞎搞事,让你的实用触手的生活超级艰难。每次你的收入上涨,你的生活方式触手就决定把它想要和期待的标准抬高一档,让你的实用触手一直陷在屎坑里努力覆盖所有开销,免得你的信用卡债务疯涨。你的个人触手有一堆奇奇怪怪的需求,占用大量时间,而且往往不怎么赚钱。而且虽然你的实用触手完全愿意直接找你的有钱叔叔要点钱帮个忙,但你的社交触手明令禁止向别人开口要钱,理由是「这形象不好看」,你的个人触手也跟着附和:「对啊,我们比那种做法要高一档。」</p><p>情况就是这样。你脑袋里住着这只渴望章鱼,长着五条触手(或者你的章鱼有几条就是几条),每条触手都有自己的小算盘,而且经常互相打架。然后每条触手上还有一堆各自独立的渴望,它们之间也经常内讧。如果这还不够乱,有时候你甚至会在<em>同一个</em>渴望内部经历激烈的内心冲突。比如当你想追随自己的热情时,却搞不清自己到底最热衷于什么。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/Passion-argument.png" target="_blank" rel="noreferrer"><img src="'+v+'" alt=""></a></p><p>或者当你极度渴望被人尊重,却又想起来:能赢得社会某个群体死忠尊重的职业,在其他群体那里往往只会得到耸肩,甚至在另一些群体眼里还会被鄙夷地翻白眼。</p><p>或者当你决定要满足自己帮助他人的冲动时,才发现——你身上那个想要投身于缓解人类最重大生存风险的部分,对你身上那个更愿意为本地社区做出切实积极影响的部分怀有明显的鄙视——而你身上那个一想到当今世界上还有数百万人喝不上干净水就受不了的部分,又觉得前两种渴望冷酷无情。</p><p>所以是的,你的渴望章鱼很复杂。历史上没有任何一个人能够让自己的整只章鱼都得到满足——这就是为什么你永远不会看到它笑得完全合不拢嘴。人类的渴望是一场关于选择、牺牲和妥协的游戏。</p><p><strong>解剖章鱼</strong></p><p>带着这个认识,我们回到你的「想要之盒」。当我们思考自己的职业目标、恐惧、希望和梦想时,我们的意识只能接触到渴望章鱼的净输出——通常由它嗓门最大的那几个声音组成。只有深入挖掘我们心灵的潜意识,才能看清真正发生了什么。<a href="#footnote-6-6721">6</a></p><p>酷的地方在于,我们每个人都有这个能力。你潜意识里的东西就像房子地下室里的东西。它不是禁区——它只是在地下室里而已。我们随时都可以下去看看——只是需要 A)记得房子还有个地下室,以及 B)真的花时间和精力下去,尽管下去这件事可能挺糟心的。</p><p>那就让我们下到你心灵的地下室去找那只章鱼吧。除非你是那种极其擅长分析自己潜意识的人,否则地下室里可能会很黑,你很难看清你的章鱼。开灯的方法是:先辨认出你的意识目前对自己的渴望和恐惧了解多少,然后把它拆开来看。</p><p>比如说,如果有某条职业道路听起来让你觉得棒极了,那就把它拆开分析。到底是哪些触手在渴望这条职业——具体又是这些触手上的哪些部分?</p><p>如果你现在没有在为那个你号称向往的职业努力,试着搞清楚为什么。如果你觉得是因为害怕失败,那就把<em>这个</em>拆开来看。对失败的恐惧可能来自任何一根触手,所以这个分析还不够具体。你要找到恐惧的具体来源。是社交触手在怕丢脸、怕被别人评判为不够聪明、怕在暧昧对象眼里显得不够成功?是个人触手在怕自己的自我形象受损——怕坐实那个一直缠着你的、对自己的怀疑?是生活方式触手在怕被迫降级居住条件、怕给现在这种可预测的生活带来压力和不稳定?又或者,那种对生活条件降级的恐惧其实并不是来自生活方式触手,而更多来自社交触手——换句话说,有没有可能你其实对换公寓这件事本身无所谓,但特别在意生活降级会向朋友家人传递出什么<em>信号</em>?或者是不是有些财务承诺你此刻根本抽不了身,你的实用触手正在真心恐慌:万一这次职业转型比预期花更长时间、甚至根本走不通,你要怎么维持生计?又或者是这里面几种合在一起,共同制造了你不敢纵身一跃的恐惧?</p><p>也许你觉得阻挡你的其实并不是对失败的恐惧,而是别的什么。也许是对身份转变的畏惧——内在和外在的身份都会随着这种职业变动而不可避免地改变。也许是惯性沉重的分量——一种对改变的强烈抗拒——它似乎独立存在,压过你所有其他的向往。不管哪种情况,你都得把这份感觉拆开,问自己究竟是哪些触手在如此抗拒身份转变,或者被惯性推着走。</p><p>也许你渴望变富。你幻想着一年挣 120 万美元的生活,并且感到一股巨大的动力想让它成真。在特定情境下,五根触手都可能各自出于自己的理由渴望财富。把它拆开。</p><p>当你拆解这股赚钱的内在驱动力时,也许你会发现,它的核心其实更多是想要一种安全感,而不是巨额财富。这个也可以继续拆。最简单意义上的安全感渴望,不过是实用触手在干实用触手该干的事。但也许你真正想要的并不是基本的安全,而是生活方式触手或社交触手所要求的某种奢华水准的保障。又或者,你真正想要的是那种夸张到已经不能叫&quot;安全感渴望&quot;的极致安全——它其实可能是生活方式触手中情绪健康那一块发出的冲动,想要缓解一种从小被灌输、几乎与实际财务状况无关、却让你终生挥之不去的强迫性财务焦虑。</p><p>所有这些问题的答案,都藏在你「渴望章鱼」的某一条触手上。通过问这些问题、挖得足够深,去辨认出各种渴望的真正根源,你就开始点亮地下室的灯,逐渐认识这只章鱼的全部复杂面貌。</p><p>你也会开始明白,内心的哪些渴望在你脑中喊得最响,在你的决策过程中拉力最大。很快,一个渴望的等级体系就会浮现出来。你会辨认出那些嗓门大、说了算的渴望;那些扯着嗓子喊、却被章鱼里更高优先级的部分不断挤到一边的渴望;还有那些似乎已经认命、安于低位的渴望。</p><p><strong>寻找冒名顶替者</strong></p><p>我们进展不错——但才刚刚开始。一旦你对自己的渴望章鱼有了相对清晰的图像,就可以开始真正的工作了——这项工作发生在潜意识再往下一层的地方,地下室的地下室里。在这儿,你可以布置一个小小的审讯室,把每一条渴望一个一个地押下来盘问。</p><p>你会先问每一条渴望:你是怎么跑到这儿的?你为什么长成这样?欲望、信念、价值观和恐惧,并不是凭空出现的。它们要么是你内在的意识随着观察和人生经验的涌入慢慢发展出来的,要么是别人从外部植入你身上的。换句话说,它们要么是「厨师你」的产物,要么是「炊事员你」的产物。</p><p>所以在你这个阴森的审讯室里,目标就是揪住每一条渴望的脸,看看它到底是真正的你,还是别人<em>伪装</em>成的你。</p><p>你可以通过玩「为什么游戏」来揪它的脸。你先问出第一个「为什么」——<em>我为什么想要这个?</em>——然后得到某个「因为」。接着继续。这个特定的「因为」为什么会让你想要你现在想要的东西?这个特定的「因为」又是从什么时候开始对你有了如此大的分量?你会挖到「因为」背后更深的「因为」。如果你一直这样挖下去,通常会发现三种情况之一:</p><ol><li><p>你把这个「为什么」追溯到源头,揭示出一条通过深度独立思考发展而来的、货真价实的漫长演化链条。你揪住它的脸,确认这层皮是真的。</p></li><li><p>你把「为什么」一路追溯回去,发现最初的那个「因为」其实是别人塞进你脑子里的——<em>我想我之所以有这个价值观,只是因为我妈多多少少把它强加给了我</em>——然后你意识到,你从来没真正停下来考虑过自己是不是独立地认同它。你从没问过自己,你积累的人生智慧是否真的配得上你对这个核心信念所抱有的坚定程度。这种情况下,那个渴望被揭穿成了冒牌货,只是在假装是你自己真实的渴望。你一把撕下它的脸,发现那是张面具,底下露出的是当初把这个渴望安装进你脑袋的那个人。</p></li><li><p>你顺着「为什么」一路追,追着追着就在一片「我就是知道啊,因为它就是对的!」的迷雾里迷路了。这有可能是真正属于你的东西,也可能只是 #2 的另一种变体——只是在这一次,你想不起来这种感觉是什么时候被塞进你脑子里的。你内心深处某个地方,会隐约知道到底是哪一种。</p></li></ol><p>在 #1 的情况下,你可以为自己像厨师一样培育出了这一部分的自己而感到自豪。这是真实的、来之不易的感觉或价值观。</p><p>而在 #2、或许还有 #3 的情况下,你会发现自己被骗了。你趁自己没注意的时候,让别人偷偷爬上了你的渴望章鱼。就那个特定的信念而言,你是个照着别人食谱做菜的厨子——一个背诵别人脑袋里的欲望和恐惧的听话机器人。</p><p>有那么一种可能:你是个不寻常的智者,一番审视之后,发现这只章鱼基本上是你自己养大的,而且一直保持更新。但更有可能的是,你和我以及我的大多数朋友差不多——审讯室里揭穿了一些明确的冒牌货,或者至少充满了模棱两可。比如,揭开某张面具,你会发现底下是你妈。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/mask-1.png" target="_blank" rel="noreferrer"><img src="'+A+'" alt=""></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/mask-2.png" target="_blank" rel="noreferrer"><img src="'+x+'" alt=""></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/mask-3.png" target="_blank" rel="noreferrer"><img src="'+C+'" alt=""></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/mask-4.png" target="_blank" rel="noreferrer"><img src="'+T+'" alt=""></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/mask-5-1.png" target="_blank" rel="noreferrer"><img src="'+E+'" alt=""></a></p><p>你会揭下另一些面具,发现底下是更宽泛的世俗智慧的价值观和判断,或是你身边这个社区的观点,或是你这一代主流文化里被认为「酷」的东西,又或者是你最亲密的朋友圈子里的小圈子文化。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/mask-6.png" target="_blank" rel="noreferrer"><img src="'+S+'" alt=""></a></p><p>有时候你顺着「为什么—因为」的路径追到尽头,发现那不过是某本著名小说里的哲学,或是你某位偶像明星在访谈里说过的一句话,又或者是你哪位教授反反复复念叨的一个强硬观点。</p><p>你甚至可能会发现,你的一些渴望和恐惧其实是你自己写下的……在你 7 岁的时候。就像一个童年梦想被刻在了你意识的背面,让你相信这才是你<em>真正</em>想要的东西,当你<em>真的</em>对自己诚实的时候。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/mask-7.png" target="_blank" rel="noreferrer"><img src="'+H+'" alt=""></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/mask-8-1.png" target="_blank" rel="noreferrer"><img src="'+Y+'" alt=""></a></p><p>这个审讯室大概不会是什么好玩的地方。但这段时间花得值——因为你不是 7 岁的你自己,就像你也不是你的父母、你的朋友、你所在的世代、你的社会、你崇拜的偶像、你过去的决定或者你最近的处境。你是当前年龄的你——唯一一个真正有资格去想要或不想要你所想要和不想要的东西的人,也是你自己唯一有资格的那个版本。</p><p>需要说清楚的是,这并不是说按照一位睿智的父母、一位著名哲学家、你尊敬的朋友或者年轻时的你所秉持的信念去生活就是错的。谦逊的人<em>从定义上</em>就是可以被影响的——各种影响是每个人身上重要且不可避免的一部分。关键的区别在于:</p><p>你是把外部影响的言论当作<em>信息</em>——由一个真实的内在自我持有和思考,并经过深思熟虑之后决定接纳的信息?还是这些影响本身就在你脑子里,<em>伪装成</em>内在的你?</p><p>你和某个你认识的人想要同样的东西,是因为你听他们谈论过,你把它和自己的人生经验放在一起思考过,最终你判断——至少目前——你同意他们?还是因为你听到某人谈论他们想要什么或害怕什么,然后你心想:&quot;我什么都不懂,而这人懂,所以他们说 X 是真的,那肯定就是真的&quot;——然后你就把这些想法刻在脑子里,从此再也没觉得需要质疑它?</p><p>前者是厨师干的事。后者是你在扮演一个听话的机器人时干的事。而当你在某个时刻脑子里冒出&quot;别人比我自己更有资格当我&quot;这种念头时,你就变成了一个机器人。</p><p>好消息是,所有人都会犯这个错——而你可以修正它。就像你的潜意识只要你想看就摆在那里可以看一样——它也摆在那里可以修改、更新、重写。这是你的脑子——你想拿它怎么办都可以。</p><p>所以是时候进行一些驱逐了。戴着面具的冒名顶替者必须走人。哪怕是老爸老妈也一样。</p><p>做完这一切之后,你的章鱼可能看起来有点光秃秃的,让你有种连自己是谁都不知道了的感觉。我们通常会把这种感觉当成一种糟糕的感觉,甚至是一场存在主义危机,但其实这意味着你做得比大多数人都好。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/roller-coaster-1-2.png" target="_blank" rel="noreferrer"><img src="'+N+'" alt=""></a></p><p>从天真的过度自信跌落到明智、现实的谦卑,这个过程从来都不好受,但在过山车还在第一个悬崖上时就把它停下、逃避这种痛苦——事实证明很多人正是这么做的——并不是什么好策略。智慧和知识多少并不相关,它和是否触碰到现实相关——重点不是你在图上多靠右,而是你离那条橙线多近。智慧一开始很疼,但那是真正成长唯一发生的地方。讽刺的是,世界上那些「停在悬崖上」的人,喜欢让那些更明智、更勇敢的、住在山谷里或持续攀登的人自我感觉不好——因为他们根本没搞懂「认识自己」是怎么回事。他们还没走到那一步。</p><p>真正认识自己极其困难,而且永远无法完成。但如果你已经从悬崖上摔下来了,你就已经通过了一道关键的成人礼,进步现在成为了可能。当你沿着橙线往上爬时,你会缓慢但坚定地开始用真实的自己重新填充你的「渴望章鱼 (Yearning Octopus)」。</p><p>此刻,那些缺失的渴望到底是什么,可能还不太明显——因为它们藏在你潜意识更深的一层。它们在地下室的地下室的地下室里——一个叫做「否认监狱 (Denial Prison)」的地方。</p><p><strong>否认监狱</strong></p><p>我们大脑里的否认监狱,是一个大多数人甚至不知道其存在的地方——它是我们把自己压抑和否认的部分关押起来的所在。</p><p>那些我们能触碰到的、真实的渴望——也就是在审讯中被证明为真实的那些——是我们真我中很容易在潜意识里找到的部分,它们就明摆着躺在那里,就在意识表层的正下方。就连我们的意识心智也很熟悉这些渴望,因为它们经常上楼跑到我们的想法里来。这些是我们与之保持着健康关系的自我部分。</p><p>但还有一些你自己的部分,它们本该住在章鱼上属于它们的位置,却不在那儿——你反而在那些位置上发现了冒名顶替者。你这些丢失的部分往往极难触及,因为它们一直住在潜意识深处,在一个低到几乎不存在的楼层里。几乎。</p><p>我们身上有些部分之所以被流放到地下三层,是因为承认它们、思考它们对我们来说痛苦得难以忍受。有时,我们身上新生的部分刚一诞生就被立刻关进监狱——这是我们对自身演变的否认,说白了,就是出于顽固。但还有些时候,我们身上的某个部分被关进「否认监狱」,是因为<em>别人</em>把它锁了进去。就你的渴望而言,其中一些是被那个戴着面具、鸠占鹊巢的入侵者塞进去的。如果老爸成功地让你相信你无比在乎拥有一份体面的事业,那他多半也让你相信,你内心深处那个真正想当木匠的部分并不是真正的你,也不是你真正想要的。在你童年的某个时刻,他把你对木工的热情扔进了一间又黑又潮的否认牢房。</p><p>那么,让我们鼓起勇气,一路下到你脑海地下室的地下室的地下室,看看能找到什么。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/denial-prison-1-1.png" target="_blank" rel="noreferrer"><img src="'+R+'" alt=""></a></p><p>你可能会碰到一些不太讨喜的角色。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/denial-prison-2.png" target="_blank" rel="noreferrer"><img src="'+F+'" alt=""></a></p><p>把他们留到下次再说——现在,专心去找那些被锁起来的、和职业有关的渴望。也许你会发现一份被压抑的教书热情。或者一种想成名的欲望,只不过被你所属的那个小圈子羞辱得让你不敢承认。又或者一种对大段自由闲暇时光的深深热爱——只是被你青春期那个更好色、更贪婪的自己一脚踹到楼下去了,好给一腔熊熊燃烧的野心让位。</p><p>有些真实自我的部分,你在否认监狱里是挖不出来的——那里实在太黑了。但要有耐心——既然你已经做完了盘点,也在你的章鱼身上给它们腾出了地方,它们也许就会开始慢慢冒出头来。</p><p><strong>优先级排序</strong></p><p>「渴望章鱼」审查的另一部分,则要处理你各种渴望之间的层级关系。渴望本身固然重要,但它们各自的优先级几乎同样重要。这个层级很好看清,因为它就藏在你的行动里。你可能喜欢认为「做点大胆的事」在你的排序里位置很高,但如果你眼下并没有在做什么大胆的事,那就说明:大胆对你来说无论有多重要,总有别的东西——你心里的某种恐惧或惯性——正被排在它之上。</p><p>重要的是要记住,渴望的排序同时也是恐惧的排序。章鱼里包含了任何可能让你想要或不想要追求某种职业的东西,每一种渴望的背面都是与之对应的、对反面情况的恐惧。你渴望被仰慕的背面,是害怕丢脸。如果把你对自我实现的渴望翻过来,你会看到对碌碌无为的恐惧。你对自尊的渴求的另一面,是害怕感到羞耻。如果你的行为看起来和你自认为的渴望内部等级不匹配,通常是因为你忘了考虑恐惧在其中扮演的角色。比如说,看起来像是一股坚定的成功驱动力,实际上可能是某人在<strong>逃离</strong>负面自我形象,或者试图摆脱嫉妒、不受赏识之类的感觉。如果你的行为似乎受制于一些你自认为并不那么在乎的渴望,那你多半是没有仔细审视自己的恐惧。</p><p>把渴望和恐惧都考虑进来,想想你内心的等级排序可能是什么样,然后回到那个重要的问题:「这个排序是谁定的?真的是我吗?」</p><p>举个例子,我们经常被告知要「追随自己的激情」——这就是社会在说「把你的激情类渴望放在等级的最顶端」。这是一条非常具体的指示。也许这对你来说是对的,但也很有可能不是。这是你需要独立去评估的事。</p><p>要把这件事做对,我们试着从第一性原理出发,基于我们真正是谁、我们如何随时间演变、以及此刻对我们真正最重要的是什么,来做一次全新的排序。</p><p>这不是看哪些渴望或恐惧的声音最大、哪些恐惧最切身——如果是那样,你就是在让冲动来掌控你的人生方向盘。做排序的那个人是<strong>你</strong>——那个正在读这篇文章、能够观察你的章鱼并客观看待它的、意识的小小中心。这里涉及到另一种妥协。一方面,你要努力调用你一生中积累的所有智慧,主动地对价值观做出决定——决定你真正认为<strong>重要</strong>的是什么。另一方面,这也关乎自我接纳和自我慈悲。有时候你会有一些强烈到无法否认、但你并不特别为之骄傲的渴望——不管你喜不喜欢,它们都是你的一部分,而当你忽视它们时,它们可能会持续散发臭味,让你痛苦不堪。构建你的渴望等级,是在「重要」和「你」之间的一种取舍。把更高的优先级给你更高尚的品质大概是个不错的目标,但偶尔给一些不那么高尚的方面也扔根骨头也没关系——具体取决于你决定把界线画在哪里。知道什么时候接受自己不那么高尚的一面、什么时候彻底拒绝它,这本身就是一种智慧。</p><p>为了把这一切整理清楚,我们需要一个好用的系统。你可以自己琢磨什么方式适合你——我个人喜欢架子这个比喻:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/yearning-hierarchy-2.png" target="_blank" rel="noreferrer"><img src="'+L+'" alt=""></a></p><p>这把东西分成了五类。绝对最高优先级的内在驱动可以放进那个特别的、不可协商的碗里。这个 NN 碗(non-negotiable,不可协商)是留给那些对你 <em>无比</em> 重要的渴望的——重要到你想基本保证它们一定会实现,如果必要的话,可以牺牲其他所有渴望。这就是为什么历史上很多传奇人物出了名地一根筋——他们的 NN 碗里有一个极其强烈的渴望,把他们推向了世界闻名的高度,常常是以牺牲人际关系、生活平衡和健康为代价。这个碗很小,因为它应该被非常克制地使用——如果用的话。可能只放一样东西。或者 <em>可能</em> 两三样。往 NN 碗里塞太多东西会抵消它的威力,那就跟碗里什么都没放没啥区别了。</p><p>你的顶层渴望集合基本上就是决定你职业选择的主要因素——但顶层的位置也应该少给(所以这个架子并不大)。摆放位置的关键既在于优先化,也在于去优先化。你不只是在选择自己哪些部分对你的幸福最重要,你也是在选择哪些部分要有意让它们得不到满足,甚至直接被压制。不管你的等级体系长什么样,总有一些渴望会觉得很不爽,总有一些恐惧会感觉在被持续攻击。这是不可避免的。</p><p>这就是为什么大多数渴望应该放在中层架、底层架或者垃圾桶里。中层架适合放你身上那些不那么高尚、但你决定接纳的品质。它们值得你分一些注意力。而且它们经常会主动索取——你身上的核心部分不会安安静静地接受被冷落,如果被忽视,它们有时候真的能毁掉你的生活。</p><p>剩下的大多数会最终落到底层架。把自己的一部分放到底层架就是在告诉它:&quot;我知道你想要这些东西,但目前,我决定别的事情更重要。我保证过段时间会再回来看看你,等我掌握更多信息之后,如果我改主意了,你就能升级到更高的架子。&quot;理解底层架的最好方式是这样:你能说服越多的渴望接受底层架的位置,你的顶层架和 NN 碗里的渴望就越有可能得到它们想要的。同样,你放在 <em>顶层</em> 架上的渴望越少,顶层架上的这些就越有可能茁壮成长。你的时间和精力极其有限,所以这是一场零和妥协。业余玩家常犯的错误就是对 NN 碗和顶层架太慷慨,而对那个大大的底层架太吝啬。</p><p>然后是垃圾桶,用来装那些你彻底拒绝的欲望和恐惧——那些从根本上违背了你最智慧自我想要成为的样子的部分。人们内心冲突的相当一部分都源自垃圾桶,而对垃圾桶的掌控是正直和内在力量的重要组成部分。但和你层级结构中的其他决定一样,你判断什么算垃圾的标准应该源自你自己深入的思考,而不是别人告诉你什么是、什么不是垃圾。</p><p>在你进行这个艰难的排序过程时——不可避免地,有时会遭到那些被降级、心怀不满的渴望的尖叫抗议——记住,房间里唯一有智慧的人就是你。渴望和恐惧都很没耐心,也很不擅长看大局。哪怕是看起来很高尚的渴望,比如道德触手上的那些,也没法像你一样理解整体图景。许多为让世界变得更好做出了惊人贡献的人,起初走上那条路时,动机其实是自私的——比如财富或个人成就感——这些动机他们的道德触手一开始很可能是讨厌的。章鱼不会是房间里那个明智的大人——那是你的工作。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/octopus-no-bones-1.png" target="_blank" rel="noreferrer"><img src="'+D+'" alt=""></a></p><p>最后,我们稍后还会更详细地讨论,这不是一个永久性的决定。恰恰相反——这是一份用浅铅笔写的草稿。这是一个假设,你可以通过实际去过这种层级结构的生活,来测试它,然后修正它。</p><p>你的「想要之盒」已经就绪。现在我们来看看你的「现实之盒」。</p><p><strong>深度分析,第二部分:你的现实之盒</strong></p><p>「想要之盒」处理的是你觉得自己想要什么。「现实之盒」处理的是什么是<em>可能的</em>。</p><p>但当我们审视「想要之盒」时,已经很清楚了——它不一定基于你真正想要什么,而是基于你<em>以为</em>自己想要什么——你<em>习惯性</em>地想要什么。</p><p>「现实之盒」也是同样的情况。它并不向你展示现实,它展示的是你对现实可能是什么样的最佳猜测——你对现实的<em>感知</em>。</p><p>自我反思的目标就是让这两个盒子尽可能地接近真实。我们希望自己感知到的渴望是内心真实自我的真实反映,也希望我们对什么是可能的信念能接近于实际上可能的事。在审视「想要之盒」时,我们掀开了它的引擎盖,找到了它的设置——你的渴望和恐惧。而当我们掀开「现实之盒」的引擎盖时,看到的是一堆<em>信念</em>。</p><p>在职业可能性这件事上,你面对的是两组信念:关于世界的信念,以及关于你自己潜力的信念。要让某个职业选项进入你的「现实之盒」,你在那个领域的潜力就必须能匹配上在该领域取得成功的客观难度。</p><p>而人就是人,我们可能在这个比较的两边都评估得挺糟糕的。</p><p>我不知道你是怎么看待职业路径难度的,但根据我的经验,人们通常是这么看的:</p><p>有一类传统职业——医学、法律、教书、或者往公司的阶梯上爬,诸如此类——这些职业有可预测的、既定的路径。只要你还算聪明、肯下功夫,最后就能落到一个成功稳定的位置。</p><p>然后有一类不那么传统的职业——艺术、创业、非营利工作、政治,等等——这些就是万金油牌了。成功和稳定都没保障,想登顶要么靠彩票式的运气,要么靠遗传彩票赐予的天赋,或者两者的某种组合。</p><p>这些假设完全合理——前提是你活在 1952 年。你对职业世界的看法、对成功需要什么的看法,和你的渴望一样需要被彻底揭穿——而我怀疑,在这些看法背后的大多数东西,你都会发现是又肥又大的传统智慧 (conventional wisdom)。你可能先揭开某个信念的面具,看见的是你父母、你的朋友、或你大学的就业指导老师——但如果你继续揭,扯下<em>他们</em>的脸,你通常会发现那也是一副面具,传统智慧就藏在后头。一种普遍观念、一种共同看法、一个常被引用的统计数据<a href="#footnote-7-6721">7</a>——这些你自己其实一个都没验证过,可社会却把它们当福音书。</p><p>如今的世界每十年都会发生剧变,这通常会让传统智慧严重过时。可我们的大脑是为一个更古老的、几乎什么都不变的世界设计的,所以我们全都像厨师那样推理,把传统智慧等同于真理。</p><p>这些问题接着延伸到我们看待自己潜力的方式上。当你高估了天赋对一个人职业发展的影响——同时又把天赋和技能水平混为一谈——你就不会对很多路径的成功几率感到乐观。因为我们更了解传统职业的轨迹,我们在传统职业上不太容易犯这个错。一个医学院一年级新生看到一位经验丰富的外科医生在做手术,他心想:「我总有一天能到那儿——只要下大约二十年的苦功。」但当一位年轻的艺术家、创业者或软件工程师看着他们领域中相当于那位资深外科医生的人物时,他们更可能想:「哇,看他们多有天赋——我远远比不上,」然后陷入绝望。还有另一种常见的观念,认为在非传统职业里出人头地的人,都是在某个时刻遇到了某个「大突破」,就像刮中了幸运刮刮乐一样——而我认识的人里,想拿自己的职业赌刮刮乐的可不多。</p><p>关于伟大职业是如何发生的,我们往往抱有一大堆错觉和误解,以上只是几个例子。那么让我们头脑风暴一下它实际上可能是怎么运作的:</p><p><strong>职业版图</strong></p><p>我基本上完全不知道。而且我觉得大多数人也不知道。事情变化得太快了。</p><p>但这恰恰是关键所在。如果你能想办法看清外面真实的职业版图,那你就比绝大多数人都占了巨大的优势——因为大多数人手里那本&quot;操作说明书&quot;,就是所谓的传统智慧。</p><p>首先,是宏观的版图——今天这个社会里,一个人可能拥有的所有工作的集合。我目前的岗位描述是:&quot;写一些 8000 到 40000 字的文章,内容五花八门,带脏话和火柴人插图,更新极其没规律。&quot;你觉得传统智慧手册里,会有符合这个描述的岗位空缺吗?今天的版图由成千上万种选项构成——有些已经存在了 40 年,有些则是三个月前因为某项新技术的出现才刚刚成为可能——而且按照如今世界的运作方式,如果你想要的那个选项还不存在,你多半可以自己创造出一个。压力挺大,但也无比令人兴奋。</p><p>其次,是每一条具体的职业路径。一条职业路径就像一块游戏棋盘。传统智慧的书架上,只放着今天可用棋盘中一小部分的说明书——就算有说明书,通常也只告诉你这个游戏过去是怎么玩的,尽管当前的棋盘早已大幅演化,出现了新类型的机会、新的规则和新的漏洞。今天当你考虑一条职业路径时,想要准确评估它是什么样、它青睐哪种优劣势组合,你必须先搞清楚这个职业当前的棋盘长什么样。否则,就好比你根据自己的身高和力量来评估自己成为职业篮球运动员的机会,却没意识到——比方说——篮球已经进化了,现在是在超大球场上打,场上有 10 个 7 英尺高的篮筐,而当前的比赛更看重速度而非身高和力量。</p><p>这是个好消息。很可能有几十条精彩的职业路径能完美契合你的天然优势,<em>而且</em>,那些路径上大多数试图成功的人,用的可能是过时的规则手册和攻略指南。如果你能真正看懂棋盘的样子,并按照现代规则去玩,你就拥有巨大的优势。</p><p><strong>你的潜能</strong></p><p>这就把话题引到了你和你独有的优势上。我们不仅会基于错误的棋盘去评估自己的优势(就像上面那个篮球的例子)——就算我们脑子里装的是<em>正确的</em>棋盘,我们也常常没法准确识别出这个游戏真正需要的优势。</p><p>评估你在某条职业路径上的胜算时,关键问题是:</p><p><em>给你足够的时间,你能不能在这个游戏里练到足够好,好到有可能达到你心目中对这份职业的成功定义?</em></p><p>我喜欢把这段「玩这场游戏玩到足够好、足以成功」的旅程看作一段距离。距离的起点是你现在所在的位置——A 点——终点是你达成自己定义的成功,我们可以用一颗星星来表示。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/A-star-1-1.png" target="_blank" rel="noreferrer"><img src="'+J+'" alt=""></a></p><p>这段距离的长度,取决于 A 点在哪里(你目前走到了哪一步),以及那颗星星在哪里(你对成功的定义有多宏大)。</p><p>所以,如果你是一个刚毕业、主修计算机科学的大学生,而你的职业目标是在谷歌当一个爬到中层的工程师,那你的距离可能长这样:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/A-star-2-1.png" target="_blank" rel="noreferrer"><img src="'+V+'" alt=""></a></p><p>但如果你从没做过任何计算机相关的事情,而你的职业目标是成为谷歌最顶尖的工程师,那你要走的路就长得多了:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/A-star-3-1.png" target="_blank" rel="noreferrer"><img src="'+j+'" alt=""></a></p><p>如果你的目标是打造出下一个谷歌,这条路会变得长得多、多得多。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/A-star-4-2.png" target="_blank" rel="noreferrer"><img src="'+M+'" alt=""></a></p><p>读到这里,传统智慧可能会作为一个声音出现在你脑子里,指出:光是把某项技能练到足够好,其实并不保证成功——你可能在一条职业路径上抵达了那颗星星,却发现自己还是没「成」。</p><p>这基本上是错的,因为它误解了这颗星星。星星要衡量的不是某项具体技能的水平——比如编程能力、演技或商业头脑——它衡量的是整个<em>游戏</em>。在传统职业里,游戏通常比较直接——如果你想成为顶尖外科医生,而你把手术做得极其出色,那你大概就已经命中星星、也会拥有属于你的职业生涯。但在不那么传统的职业里,游戏棋盘上往往涉及多得多的因素。命中「我想成为一名著名演员」这颗星星,不是简单地把演技练到和摩根·弗里曼 (Morgan Freeman) 一样好,而是要把整个演员<em>游戏</em>玩到大多数电影明星在爆红时所达到的水平。演技只是这个拼图中的一块——你还需要有本事把自己送到有权力的人面前,需要精明的个人品牌运作,需要疯狂的乐观精神,需要荒谬程度的拼劲和坚持,等等。如果你把这<em>整个</em>游戏——它的每一个组成部分——都玩得足够好,那你成为一线电影明星的概率其实相当高。这才是命中星星的真正含义。</p><p>但传统智慧根本搞不懂非传统职业是怎么运作的——它只从一个狭窄的角度去理解成功:才华加努力。当职业路径的棋盘上有远比这更多的东西在发生时,传统智慧只能双手一摊,把它归结为「运气」。在传统智慧看来,想成为电影明星需要一点才华,但大部分还是靠中一张罕见的刮刮乐头奖。</p><p>那么你要怎么估算自己抵达某颗特定星星的机会呢?一切都归结为一个简单的公式:</p><p>距离 = 速度 × 时间。</p><p>在我们的情境下,更贴切的表达可能是:</p><p>进展 = 步速 × 坚持。</p><p>你在任何一场职业追寻中的前景,取决于 A) 你在这份职业的「游戏」中能够精进的步速,以及 B) 你愿意花多长时间去追逐那颗星星。让我们来分别聊聊这两点:</p><p><strong>步速</strong></p><p>是什么让一个人在职业游戏中精进得更慢或更快?我认为归结为三个因素:</p><p><strong>你的「厨师程度」。</strong> 正如我们之前所讨论的,厨师用新鲜的眼光看世界,基于自己所观察到的和亲身经历过的东西得出结论。厨子则是照着别人的菜谱得出结论——在职业这件事上,菜谱通常就是传统智慧。职业是复杂的游戏,几乎每个人一开始都玩得很烂——然后厨师通过一个持续的循环快速精进……</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/Chef-Strategy-Loop-1.png" target="_blank" rel="noreferrer"><img src="'+K+'" alt=""></a></p><p>……而厨子的精进速度慢得像蜗牛,因为他们的策略无非是照着一份本身几乎不变的菜谱做菜。更要命的是,在这个职业游戏不断演化、不断变形的世界里,厨师的战术可以实时进化、跟上节奏。与此同时,厨子的菜谱只会越来越过时——而他们对此浑然不觉。这就是为什么我相当确信,至少对于比较非传统的职业而言,你的「厨师程度」是决定你精进步速最重要的单一因素。</p><p><strong>你的工作投入度。</strong> 这一点很显而易见。一个每年 50 周、每周工作 60 小时投入自己职业的人,前进的速度差不多是每年 40 周、每周工作 20 小时的人的四倍。选择均衡生活方式的人,会比一心一意的工作狂走得慢。有懒惰或拖延倾向的人,会比擅长稳定输出工作日的人落后一大截。经常从工作中抽离去发呆或摸手机的人,单位工作小时的产出会比练就深度专注的人少。</p><p>**你的天赋能力。**天赋确实重要。更聪明、更有天分的人在一门游戏上的进步速度会比天赋平平的人更快。但智力和才华只是这里涉及的两种天赋能力。机灵和世故也很重要,而这些品质并不总是与纯粹的智力相关。根据职业类型的不同,社交能力也可能至关重要。在许多职业中,讨人喜欢的(或善于微妙操控的)人相比那些不太讨喜的人有着巨大优势——而且喜欢社交的人随着时间推移会投入更多与人打交道的时间,建立起比反社交类型更深的人脉关系。</p><p>其他东西,比如现有的人脉、现有的资源、现有的技能当然也重要,但它们不是速度的组成部分——它们是 A 点位置的一部分。</p><p><strong>坚持</strong></p><p>当我说坚持的时候,我指的是长期坚持(而不是日常的工作态度)。坚持比速度更简单。你愿意花多少年去追一颗星,你就能在通往那颗星的路上走多远。一辆以 30 英里/小时行驶但 15 分钟后就不开了的车,走的距离远远比不上一辆以 10 英里/小时行驶两小时的车。</p><p>这就是为什么坚持如此重要。一个决定只愿意给梦想事业三年时间试一试、之后就转投备胎计划的人,基本上已经把自己从追梦的机会中除名了。你有多牛逼都无所谓——如果你在两三年没有突破后就放弃,你就不太可能成功。几年时间根本不足以跨越通往那些最酷成功之星所需的漫长距离,不管你的速度多么惊人。</p><p><strong>你真正的优势和劣势</strong></p><p>带着我们「速度乘以坚持」的等式,让我们重新审视一下优势和劣势的概念。不是说「优势和劣势」这个概念不好——而是我们思考它的方式全错了。当我们列出自己的优势时,我们往往列的更多是自己现有技能所在的领域。相反,优势应该完全关于速度和坚持的品质。原创性(或缺乏原创性)应该是讨论的关键组成部分,让灵活性和谦逊(主厨的标志性特质)这样的品质成为显著的优势,而固执<a href="#footnote-8-6721">8</a>或智力懒惰(典型的厨子特质)则是重要的劣势。工作态度上的微妙之处,比如深度专注的本事或者拖延的倾向,也应该是讨论的重要部分,天赋之外的自然能力,比如世故和讨喜程度,同样如此。与坚持相关的品质,比如韧性、决心和耐心,应被视为有前途的优势,而那种迫切想要尽快显得成功的社交触角,则应被视为一面鲜艳的红旗。</p><p>最重要的是,这些项目不应该被当作你当下状态的快照来讨论,而应该从你在每一项上的<em>改进潜力</em>来看。如果你把一个篮球第一次递给 25 岁的迈克尔·乔丹 (Michael Jordan),他会打得很烂。但把篮球称为他的「弱点」就大错特错了。相反,你会想看他接下来六周的训练,评估他进步的斜率。这个道理适用于具体技能——但如果你专注去做,大多数一般性的节奏和坚持类特质也<em>同样</em>可以被打磨和提升。</p><p><strong>填充现实盒子</strong></p><p>你真正的现实盒子字面上应该囊括所有你认为一个大幅提升过的自己、耗尽一生努力后能够达到你所能接受的「成功」最低星标的职业道路。这会是一个大到离谱的列表,只排除那些明显以你在该道路上的最大可能速度也远远走不完的路径(比如我追求奥运花样滑冰运动员的职业生涯)。但花一分钟停下来,反思一下你完整现实盒子的辽阔程度仍然是有用的——单是承认有多少选项其实向你敞开,就能让你进入正确的心态。<a href="#footnote-9-6721">9</a></p><p>所以为了效率高一点,我们只关心现实盒子中真正可能进入你选项池 (Option Pool) 的部分(也就是韦恩图中「想要盒子」和「现实盒子」重叠的中间区域)。带着这个前提来完成我们的现实盒子审计,我们需要评估:</p><p>**1) 总体格局。**尽力评估当今世界的职业格局——所有可用的(或可以创造出来的)选项的完整范围。</p><p>**2) 具体棋盘。**对于任何听起来有那么一点点意思的职业,思考一下这个职业当前棋盘的情况——参与的各方、最近别人是怎么获得成功的、这个游戏最新的规则、最近有什么新漏洞正在被人利用等等。</p><p>**3) 起点。**对于那些道路,基于你目前与该领域相关的技能、资源和人脉,评估你的起点。</p><p>**4) 成功点。**思考终点在哪里,以及每条线上你的星标应该放在什么位置。问问自己,要在这条职业道路上感到不后悔选择了它,你至少需要达到什么级别的成功。</p><p>**5) 你的节奏。**基于你当前与节奏相关的优势,以及你觉得自己在每一项上还能提升多少(换句话说,你的速度能<em>加速</em>到什么程度),初步估算一下你在这些不同棋盘上的进步节奏。</p><p>**6) 你的坚持程度。**评估一下你愿意在这些不同道路上分别投入多少时间。</p><p>现在只剩数学问题了。你把游戏棋盘变成一条直线,在上面标出起点和成功之星,它们共同决定了你面前的各段距离,然后对每一条路径,把你的速度乘以你的毅力水平。如果某条职业路径上「速度 × 毅力」的乘积看起来能匹配得上这条路的总长度,那这份职业就进入了你的现实盒 (Reality Box)。当然,上述任何因素都不可能得到精确数值,但至少知道自己在用什么方程,是件好事。</p><p>一次从第一性原理出发的现实盒审计,可能会让一些过于乐观的人回到地面,但我怀疑对大多数人来说,审计的结果会让他们感觉自己拥有的选项比想象中多得多,从而有底气把目光投向更大胆的方向。</p><p>一次好的现实盒反思,又会引出新一轮的欲望盒 (Want Box) 反思。在脑中重新审视一堆职业路径,会改变你对其中某些路径的渴望程度。当你提醒自己某份职业需要几千小时的人脉经营、或几十年不见成效的挣扎后,它的吸引力可能就没那么大了。而当你重新评估某份职业到底涉及多少运气成分后,它可能就没那么令人生畏了。还有一些职业路径,你之前根本没想过要不要,因为你压根没把它们当成真实的选项,但一番深度反思打开了你的思路。</p><p>这就到了我们这场漫长的两部分深潜之旅的终点。经过一轮相当耗神的盒子审计,我们可以回到我们的维恩<a href="#footnote-10-6721">10</a>图。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/venn-1.png" target="_blank" rel="noreferrer"><img src="'+Z+'" alt=""></a></p><p>假设有些东西已经变了,那你现在拥有一个新的选项池 (Option Pool)——一份摆在桌面上的新清单,里面既符合你的高优先级排序、又看起来可以实现。我们准备好回到分析开始之前所处的位置:此刻。带着眼前这些选项,我们可以从分析中抬起头,望向未来。</p><p><strong>把点连向未来</strong></p><p>是时候把我一开始就让你放下的那张职业规划图 (Career Plans map) 拿回来了——就是画着箭头或问号的那张。如果审计之前你的图上有一支清晰的箭头,那就看看你的新选项池。综合你反思过的一切,你目前的职业规划还有资格待在里面吗?如果答案是「有」,恭喜——你已经领先我们大多数人了。</p><p>如果没有,嗯,这是个糟糕的消息,但也是个好消息。记住,从一支假箭头变成一个问号,在人生里永远是重大的进步。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/roller-coaster-2-2.png" target="_blank" rel="noreferrer"><img src="'+$+'" alt=""></a></p><p>而且事实上,新出现的问号意味着你已经在<strong>两条</strong>过山车上完成了关键的悬崖一跃:了解你自己,以及了解这个世界。朝正确方向迈出了一大步。划掉那个箭头,加入问号阵营吧。</p><p>现在问号阵营的人得做一个艰难的选择。你得从选项池里挑一个箭头出来。</p><p>这确实是个艰难的选择——但它本<strong>不该有这么难</strong>。原因如下:</p><p>以前的职业生涯有点像一条 40 年的隧道。你挑一条隧道,一旦进去了,就是那样了。你在那个行当里干上 40 年左右,然后隧道把你从另一头吐出来,进入退休生活。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/tunnels-2.png" target="_blank" rel="noreferrer"><img src="'+G+'" alt=""></a></p><p>事实是,职业生涯可能从来就没真正像过 40 年隧道,只是看起来像而已。往好了说,过去传统的职业<strong>有点</strong>像隧道那样运行。</p><p>今天的职业——尤其是那些不那么传统的——真的真的不像隧道。但陈腐老旧的传统智慧还让很多人用那种眼光看事情,这就让本来就很难的重大职业选择变得难上加难。</p><p>当你把职业看成一条隧道时,它会让任何一个搞不清自己到底是谁、也不知道几十年后想成为谁的人陷入身份危机——而这几乎是所有理智的人的状态。它强化了这样一种错觉:我们做的工作就等于我们是谁,于是地图上的一个问号看起来就像存在意义上的一场灾难。</p><p>当你把职业看成一条隧道时,做出正确选择的赌注似乎变得巨大无比,让「选择的暴政」这种感觉爆炸式放大。对完美主义者来说尤其如此,这种感觉能让人彻底动弹不得。</p><p>当你把职业看成一条隧道时,你就失去了转换职业的勇气,哪怕你的灵魂在苦苦哀求。它让转行显得极其冒险又丢人,还暗示这么做的人是个失败者。它还让各种多面向、鲜活的中年人觉得自己太老了,已经不适合大胆转型或从零开始一条全新的路了。</p><p>但传统智慧依然告诉我们许多人:职业就是一条隧道。它这坨屎蛋糕上还要加一层糖霜——除了帮我们渴望我们其实并不想要的东西、否认我们内心深处真正的渴望、害怕根本不危险的事情、相信关于世界和我们潜力的错误观念之外——传统智慧还告诉我们职业是一条隧道,好让我们毫无必要地把自己吓个半死。</p><p>今天的职业版图不是一排隧道的阵列,而是一个庞大、复杂到不可思议、快速变化的科学实验室。今天的人不等于他们做的事——他们是复杂到不可思议、快速变化的科学家。今天的职业不是隧道,不是盒子,也不是身份标签——它是一长串科学实验。</p><p>史蒂夫·乔布斯 (Steve Jobs) 把人生<a href="https://www.youtube.com/watch?v=UF8uR6Z6KLc" target="_blank" rel="noreferrer">比作</a>连点成线,他指出,回头看过去、看那些点是如何一步步把你带到今天的位置,这很容易;但要在人生中往前连点,基本是不可能的。</p><p>如果你翻翻你那些偶像的传记,你会发现他们走过的路,更像是一长串连起来的点,而不是一条笔直、可预测的隧道。看看你自己和你的朋友,大概率也是同样的规律——根据<a href="https://web.archive.org/web/20170420130623/https://www.bls.gov/news.release/tenure.nr0.htm" target="_blank" rel="noreferrer">数据</a>,年轻人在一份工作上停留的中位时间只有 3 年(年长的人在每个点上待得更久些,但也没长多少——平均 10.4 年)。</p><p>所以把职业生涯看成一连串的点,并不是什么帮你做决定的心理小技巧——这就是事情真实发生的样子。而把职业生涯看成一条隧道,不只是没什么用——那是妄想。</p><p>同样,你只能主要专注于路上的下一个点——因为它是你<strong>唯一能</strong>搞清楚的点。你根本不用操心第 4 个点,反正你也操心不了——你从字面意义上就没资格去操心。</p><p>等第 4 个点真正到来的时候,你会知道一些现在还不知道的关于自己的事。你也会变得和现在的自己不一样,你的「渴望章鱼」也会反映出这些变化。你会比现在更了解职业版图、更了解你感兴趣的那些具体棋盘,而且你会成为一个厉害得多的棋手。当然,那个版图——以及那些棋盘——本身也会已经进化了。</p><p>超棒的网站 <a href="https://80000hours.org/" target="_blank" rel="noreferrer">80,000 Hours</a>(专门帮助有才华的年轻人思考自己的职业选择)整理了大量数据来佐证这一点:关于<a href="https://80000hours.org/2015/02/we-change-more-than-we-expect-so-keep-your-options-open/" target="_blank" rel="noreferrer">你会改变</a>、<a href="https://80000hours.org/2015/02/which-careers-will-be-automated/" target="_blank" rel="noreferrer">世界会改变</a>,以及<a href="https://80000hours.org/career-guide/personal-fit/" target="_blank" rel="noreferrer">你只有随着时间推移才会知道自己真正擅长什么</a>的数据。流行心理学家丹·吉尔伯特 (Dan Gilbert) 也很雄辩地<a href="http://www.randomhouse.com/kvpa/gilbert/" target="_blank" rel="noreferrer">描述</a>了我们在预测什么能让未来的自己幸福这件事上到底有多糟糕。</p><p>假装你现在就能搞清楚第 2、第 4 或第 8 个点该是什么,简直可笑。未来的点,是未来那个活在未来世界里、更聪明的你该操心的事。所以我们还是专注于第 1 个点吧。</p><p>如果我们把自己当成科学家,把社会当成一个科学实验室,那你眼下这份刚刚修订过的「想要-现实韦恩图」就该被看作不过是一个早期的、粗糙的假设。第 1 个点,就是你去检验它的机会。</p><p>假设检验在约会的世界里是很直观的。如果一个朋友正在苦思冥想自己想嫁给什么样的人,却从来不跟任何人出去约会,你会告诉她:「你窝在沙发上是想不明白这件事的——你得开始去约会,那才会让你搞清楚自己想要什么样的伴侣。」如果这位朋友之后来了一次相当不错的初次约会,回到家却又花好几个小时纠结这个新对象是不是「命中注定的那一位」,你还得再一次纠正她。你会说:「就凭一次约会你怎么可能知道!你得跟这个人多约几次,积累一些经验,才能学到你需要学到的东西,来做那个决定。」</p><p>我们都会同意这位假想中的朋友挺神经的,而且从根本上不理解怎么找到一段幸福的关系。所以在选择职业时,我们别学她。第 1 个点是个轻松的情境——它只是第一次约会。</p><p>这是个超棒的消息——因为如果你在地图上画的箭头只是通往你未来的第 1 个点,那画起来就没那么可怕了。「选择的暴政」的真正成因,是你精准地看到了当今世界拥有的选项数量之庞大,却又幻觉般地把那些职业当成昨日世界那种 40 年长的隧道。这是个致命的组合。把你下一个重大的职业决定重新框定为一个赌注低得多的选择,会让选项的数量变得令人兴奋,而不是令人焦虑。</p><p>这些理论上都很棒。但接下来才是难的部分。</p><p><strong>迈出你的那一步</strong></p><p>你反思了又反思、又反思,权衡、衡量、预测、考量。你选了一个点,画了一个箭头。而现在,你得真的迈出这一步了。</p><p>我们在这方面超级糟糕。我们是些容易害怕的人。我们不喜欢黏糊糊的事情,而在现实生活中迈出一大步就是黏糊糊的。如果我们身上有一丁点儿容易拖延的倾向,这里就是它现形的地方。</p><p>「渴望章鱼 (Yearning Octopus)」可以帮上忙。正如我们之前讨论过的,你在任何时刻的行为,只不过是在展现你的章鱼当下的配置状态。如果你决定了要迈出人生的一步,却怎么都迈不出去,那是因为在你的潜意识里,那些不想动的部分排位比那些想动的部分要高。你的意识层面也许试图把章鱼中那些倾向于按兵不动的部分放到较低的架子上,但你的渴望们叛乱了。你是个管不住员工的 CEO。</p><p>要解决这个问题,你得像幼儿园老师一样思考。在你的班上,一小撮 5 岁小孩正在反抗你的意愿。你会怎么做?</p><p>去跟那些捣蛋的 5 岁小孩谈谈。他们是些讨人厌、爱顶嘴的小笨蛋,但他们还是能被讲道理讲通的。跟他们说说你为什么在章鱼的等级体系里把他们排得比别人低。给他们描述一下你在「现实盒子 (Reality Box)」反思中得到的洞见。提醒他们「点点相连」是怎么运作的、以及第 1 个点其实很轻松。你是老师——自己想办法搞定。</p><p>我年纪越大,越清楚一件事:作为自己心智的幼儿园老师,那场内心的战争大概占了人生挣扎的 97%。这个世界很容易——难的是<em>你自己</em>。如果你发现自己老是没法执行自己的人生计划、兑现对自己的承诺,那你就找到了你的头号新任务——成为一个更好的幼儿园老师。在你做到之前,你的人生会被一群原始、短视的 5 岁小孩掌管,你的一切都会烂透。相信我,我懂。</p><p>如果你的内心分析真的召唤你跳到一个新的圆点,我希望在某个时刻,你能纵身一跃。</p><p><strong>跳过去之后</strong></p><p>跳到一个新圆点是一种解脱的感觉,通常伴随着相当程度的内心天翻地覆。</p><p>首先,至少在一段时间内,你在新圆点上做的事情很可能会烂得一塌糊涂。虽然你明智的那部分自我知道事情本该如此,但你不太明智的那些自我会陷入彻底的存在主义崩溃。所有那些你在章鱼排序里深思熟虑地降了优先级的恐惧,会以为有人正在谋杀它们,开始试图拨打 911。那些你确实优先考虑的渴望还没什么满足感,它们会怀疑自己一直以来对想要什么的判断是不是全都错了。那些你没有优先考虑的渴望,则会掏出吉他,为那片被你剥夺的、看起来更绿的青草地唱起情歌。这可不会太好玩。</p><p>即便一切顺利,你也会很快被提醒:渴望章鱼 (Yearning Octopus) 从根本上就是一种不快乐的生物。章鱼身上的核心部分会觉得被忽视甚至被攻击,而随着日子一天天过去,你会背负着那些你曾考虑但选择不走的道路的机会成本——那些在平行宇宙里做出别的选择的你的版本。你会想象他们在世界上假想的成就,担心你可能错过了什么。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/opportunity-cost-2.png" target="_blank" rel="noreferrer"><img src="'+I+'" alt=""></a></p><p>随着你变得更有智慧,你会学着接受一只基本上并不快乐的章鱼。你会让它抱怨,并且擅长把它调成静音,因为你知道它抱怨的方式,正是你计划好的那种。</p><p>这只抱怨的章鱼提醒着我们:为什么纯粹的、狂喜的快乐从来都不是一个合理的目标。你感到纯粹快乐的那些时刻,是暂时的、药物诱导般的幻觉——就像一段新恋情或新工作的蜜月期,或者一场期待已久的成功带来的高潮。那些时刻是一个平庸高尔夫球手一场球里的完美挥杆——它们很棒,你就该好好享受个够——但它们不是新的常态,也永远不会是。</p><p>更好的目标是<strong>满足感 (contentment)</strong>:那种令人心安的感觉——你觉得自己正在尽最大努力走一条好的人生路径;你手头正在做的事,或许有一天会成为一幅让你真正引以为傲的拼图中的一块。追逐快乐是外行的做法。而在那些你的选择和境遇恰好合力促成好结果的时刻,能感受到满足,能明白自己已经拥有了所能奢望的一切——这才是智者的境界。</p><p>人们常说要活在当下,但还有一个更宏大的概念叫做<strong>宏观在场 (macro-presence)</strong>:在你自己的人生里,广义上感到&quot;在场&quot;。如果你所在的那个职业圆点——当你真的对自己诚实时——感觉就是对的,那你就可以暂时停止思考、停止规划,一头扎进去。全景图以后再回来看——眼下,你可以把宏观画面搁在一边,埋头苦干,把全部精力奉献给当下。有那么一段时间,你可以就这么<em>活着</em>。</p><p>这样的时刻不见得能持续多久,所以要死死咬住。把你拥有的一切都投进你所选的那个圆点里。就你所知,你可能正是刚拿起第一颗篮球的迈克尔·乔丹——所以开始打球吧。</p><p><strong>下一个圆点?</strong></p><p>某一刻,你对宏观画面的良好感觉可能会变味。当这种情况发生时,你就得重新进入分析模式,搞清楚究竟是什么在让你焦躁不安。</p><p>有时候,宏观使命本身没有问题。而是你心里的那位主厨判断:这个使命本身需要一次战略性的圆点跳跃。在这种情况下,跳圆点并不是在释放坚持,而恰恰是坚持的<strong>素材</strong>。这是<strong>使命强化型 (mission-enhancing)</strong> 的圆点跳跃。</p><p>而在另一些时候,你会感到一种更阴郁的躁动——一种怀疑:也许你需要更换这个宏观使命本身。当这种感觉出现时,你得判断这份感觉究竟是来自你内心中智慧的那部分,还是仅仅来自你那些躁动不安、被排在优先级末尾的渴望。<strong>使命更换型 (mission-changing)</strong> 的圆点跳跃或许是必要的,但取决于是你的哪一部分在提出这个要求,它也可能是完全错误的选择。</p><p>在这样的时刻,重要的是要考虑你自己通常处于下面这条光谱的哪个位置:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/inertia-spectrum.png" target="_blank" rel="noreferrer"><img src="'+U+'" alt=""></a></p><p>光谱左边的人是<strong>畏跳型</strong>,水泥脚。他们的陷阱是在错误的事情上待得太久太久。右边的人是<strong>乐跳型</strong>——长翅膀的脚——他们的陷阱恰好相反:是习惯性快速退出。<a href="#footnote-11-6721">11</a>(你应该特别警惕水泥脚——心理学家认为,处在人生尽头的人最容易后悔的就是活在惯性里:一句常被说出口的悔恨是<a href="https://www.bakadesuyo.com/2012/12/top-career-regrets/" target="_blank" rel="noreferrer">「我真希望我早点退出」</a>,而老人们最常给的建议是:「<a href="https://www.bakadesuyo.com/2013/04/most-important-life-lesson/" target="_blank" rel="noreferrer">别在一份你讨厌的工作上耗着。</a>」)</p><p>这就是为什么这些内在框架很重要。它们让你有能力去分析自己冲动的来源。在我们的例子里,问题在于:你想跳槽换使命的冲动,究竟是真正的进化,还是快速放弃者偏见的产物。所以想想你的那张图。你的躁动,是不是那只章鱼配置依然正确、却在照常没完没了地哼哼唧唧?是不是走在一条对你依然正确的道路上,只是长途跋涉累了?还是说,你在跋涉的过程中,学到了关于自己或世界的新信息,修正了一些原本就跑偏的初始假设?又或者,有某种东西正在发生根本性的进化 —— 也就是某个蓝色或黄色<em>循环</em>的活动:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/venn-with-loops-small.png" target="_blank" rel="noreferrer"><img src="'+z+'" alt=""></a></p><p>如果你觉得事情已经真正发生了改变,你可能会决定再往外拉远一层,思考那个红色的大循环 —— 也就是从根本上改变你的使命:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/venn-with-big-loop-small.png" target="_blank" rel="noreferrer"><img src="'+X+'" alt=""></a></p><p>如果说职业生涯就像把一个个点连起来,那我们大概应该把「在跳点这件事上变得更明智」放在待办清单里相当靠前的位置。最好的起点就是回顾你自己的过去。用事后诸葛的手电筒和积累起来的智慧去研究自己过去的决定,就像运动员研究比赛录像一样。</p><p>回看我自己的过去,我能看到不少跳点(或者在我还在上学的时候,是职业规划的调整),其中有些现在回头看真的挺不明智。但我对过去糟糕决定、以及塑造它们的那些思维模式和行为习惯看得越清楚,将来重蹈覆辙的可能性就越小。</p><p>时刻记得自己其实挺蠢,也是一种至关重要的谦卑练习。谦卑带来的那种不安全感并不好受,不得不持续自己发明自己人生地图的负担也从来不轻松 —— 但不安全感和困难,正是你亲自掌舵这艘船的感觉。恰恰是当我们感觉太良好的时候,才有变得过度自信、思想上自满、被自己的老一套困住的风险。恰恰是当我们以为自己把人生都想明白了的时候,我们才会真正迷失方向。</p><hr><p>在你的一生中,你那些好的和坏的决定会共同协作,锻造出你独一无二的人生路径。在这个博客里,我常常写到我们的恐惧有多不理性,又能把我们拖得多惨。但对于「临终时的悔恨」这种恐惧,我们大概应该拥抱它。</p><p>谢天谢地,我从没躺在什么像临终病榻的东西上,但生命的尽头似乎有某种魔力,能让人清清楚楚地看见事物。面对死亡,似乎会让脑袋里那些其实并不是你的声音统统消散,只留下你那小小的真实自我孤零零地站在那里,静静反思。我觉得临终遗憾或许就是你的真实自我在思考那些你从未活过的人生片段——那些被别人踢进你潜意识深处的自己。</p><p>我自己的心理似乎也印证了这一点——回顾迄今为止的人生轨迹,最让我耿耿于怀的错误,都是因为别人接管了我脑袋的方向盘,压过了我真实自我那微弱、不安的声音——那些错误,我在当时的内心深处就知道是错的。我对未来的目标不是避免犯错,而是让我犯的错都是我自己的错。</p><h2 id="这就是为什么我在这篇文章里进行了如此痛苦而严苛的分析。我觉得这是人生中为数不多、值得这么较真的话题之一。其他声音永远不会停止拼命想替你过你的人生——你欠你意识最中心那个不安的小角色一个交代-把这件事想明白。" tabindex="-1">这就是为什么我在这篇文章里进行了如此痛苦而严苛的分析。我觉得这是人生中为数不多、值得这么较真的话题之一。其他声音永远不会停止拼命想替你过你的人生——你欠你意识最中心那个不安的小角色一个交代:把这件事想明白。 <a class="header-anchor" href="#这就是为什么我在这篇文章里进行了如此痛苦而严苛的分析。我觉得这是人生中为数不多、值得这么较真的话题之一。其他声音永远不会停止拼命想替你过你的人生——你欠你意识最中心那个不安的小角色一个交代-把这件事想明白。" aria-label="Permalink to &quot;这就是为什么我在这篇文章里进行了如此痛苦而严苛的分析。我觉得这是人生中为数不多、值得这么较真的话题之一。其他声音永远不会停止拼命想替你过你的人生——你欠你意识最中心那个不安的小角色一个交代:把这件事想明白。&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会通知你。</p><p>想支持 Wait But Why,可以访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><h2 id="如果你想下载这篇文章用于打印和离线分享-可以在这里购买。" tabindex="-1">如果你想下载这篇文章用于打印和离线分享,可以<a href="https://gum.co/wbw-career-path" target="_blank" rel="noreferrer">在这里购买</a>。 <a class="header-anchor" href="#如果你想下载这篇文章用于打印和离线分享-可以在这里购买。" aria-label="Permalink to &quot;如果你想下载这篇文章用于打印和离线分享,可以[在这里购买](https://gum.co/wbw-career-path)。&quot;">​</a></h2><p><strong>分析你自身情况的辅助工具:</strong></p><p><strong>一些可供书写的纸张:</strong><a href="https://waitbutwhy.com/wp-content/uploads/2018/04/WORKSHEET-octopus-1.pdf" target="_blank" rel="noreferrer">你的章鱼</a>。<a href="https://waitbutwhy.com/wp-content/uploads/2018/04/WORKSHEET-yearning-hierarchy-1.pdf" target="_blank" rel="noreferrer">你的优先级架子</a>。<a href="https://waitbutwhy.com/wp-content/uploads/2018/04/WORKSHEET-A-star-1.pdf" target="_blank" rel="noreferrer">一些路径距离</a>。<a href="https://waitbutwhy.com/wp-content/uploads/2018/04/WORKSHEET-career-dot-map.pdf" target="_blank" rel="noreferrer">你的职业点阵图</a>。</p><p>**给那些想挖得更深的人:**Alicia(WBW 各种事务的负责人)整理了<a href="https://waitbutwhy.com/wp-content/uploads/2018/04/WBW_Career-Path_Worksheet-v4.pdf" target="_blank" rel="noreferrer">一套更深入的工作表</a>。</p><p><strong>进一步探索:</strong></p><p><a href="https://80000hours.org/" target="_blank" rel="noreferrer">80,000 hours</a> 这个网站——致力于帮助年轻、高潜力人才做出重大职业选择——是个非常棒的资源。这个网站由一群超级聪明、善于思考、有前瞻性的人运营,除了网站,你还可以通过<a href="https://www.youtube.com/watch?v=iY5Vd4LH1J4&amp;list=PL-BRtcBm4Yj6ZpOG49cbHut0gtuCEVXfk&amp;index=2" target="_blank" rel="noreferrer">视频</a>或<a href="https://www.amazon.com/80-000-Hours-fulfilling-career-ebook/dp/B01M70QISP/" target="_blank" rel="noreferrer">书籍</a>的形式来吸收内容。</p><p>我读 <a href="http://sethgodin.typepad.com/" target="_blank" rel="noreferrer">Seth Godin 的博客</a> 已经好多年了。Seth 脑子里装着一大堆智慧,他每天早上以一小块一小块的形式在博客上分享出来(我通过邮件订阅)。Seth 的很多建议都适用于职业选择。<a href="http://sethgodin.typepad.com/seths_blog/2013/07/people-like-us-do-stuff-like-this.html" target="_blank" rel="noreferrer">这里有一个例子</a>(我把它改编成了本文中的一幅漫画)。</p><h2 id="eric-barker-的-博客-里全是实实在在的数据-可以帮助你做职业选择-比如-这篇-讲什么样的职业让人有成就感-或者-这篇-讲导师的重要性。" tabindex="-1">Eric Barker 的 <a href="https://www.bakadesuyo.com" target="_blank" rel="noreferrer">博客</a> 里全是实实在在的数据,可以帮助你做职业选择,比如 <a href="https://www.bakadesuyo.com/2014/08/fulfilling-career/" target="_blank" rel="noreferrer">这篇</a> 讲什么样的职业让人有成就感,或者 <a href="https://www.bakadesuyo.com/2014/02/mentor/" target="_blank" rel="noreferrer">这篇</a> 讲导师的重要性。 <a class="header-anchor" href="#eric-barker-的-博客-里全是实实在在的数据-可以帮助你做职业选择-比如-这篇-讲什么样的职业让人有成就感-或者-这篇-讲导师的重要性。" aria-label="Permalink to &quot;Eric Barker 的 [博客](https://www.bakadesuyo.com) 里全是实实在在的数据,可以帮助你做职业选择,比如 [这篇](https://www.bakadesuyo.com/2014/08/fulfilling-career/) 讲什么样的职业让人有成就感,或者 [这篇](https://www.bakadesuyo.com/2014/02/mentor/) 讲导师的重要性。&quot;">​</a></h2><p><strong>更多 Wait But Why 的人类深度剖析:</strong></p><p><a href="https://waitbutwhy.com/2016/09/marriage-decision.html" target="_blank" rel="noreferrer"><strong>结婚这个决定:要么永远拥有一切,要么永远失去一切</strong></a></p><p><strong><a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">拖延症患者为什么会拖延</a></strong></p><p><strong>还有一篇关于<a href="https://waitbutwhy.com/2014/10/religion-for-the-nonreligious.html" target="_blank" rel="noreferrer">变得更有智慧</a>的文章</strong></p><p><strong>以及几篇不那么自我反思风格的 Wait But Why 文章:</strong></p><p><strong><a href="https://waitbutwhy.com/2014/01/the-great-perils-of-social-interaction.html" target="_blank" rel="noreferrer">尴尬的社交场面</a></strong></p><p><strong><a href="https://waitbutwhy.com/2013/08/putting-time-in-perspective.html" target="_blank" rel="noreferrer">万物简史</a></strong></p><p><strong><a href="https://waitbutwhy.com/2015/08/how-and-why-spacex-will-colonize-mars.html" target="_blank" rel="noreferrer">殖民火星</a></strong></p><hr><ol><li><p>以及其他高等教育。<a href="#note-1-6721">↩</a></p></li><li><p>而且连帽衫很舒服,Allbirds 穿起来就像随时都套着袜子,牛仔裤则是那种除非你把彩色东西洒上去、否则永远不用真洗的神奇裤子。<a href="#note-2-6721">↩</a></p></li><li><p>好吃的一餐和锻炼身体也属于这一类。<a href="#note-3-6721">↩</a></p></li><li><p>我个人希望我的退休生活能像职业道路一样丰富多彩,也就是说,我得继续在「退休果园」里反思自己的道路。<a href="#note-4-6721">↩</a></p></li><li><p>你知道他其实是个渴望五爪章鱼 (Yearning Pentapus),我知道他其实是个渴望五爪章鱼,他自己也知道他其实是个渴望五爪章鱼——但咱们就别戳破了吧。<a href="#note-5-6721">↩</a></p></li><li><p>如果你想在纸上做分析,文章底部有可打印版本。<a href="#note-6-6721">↩</a></p></li><li><p>你知道 10 家餐厅里有 9 家会倒闭吗?<a href="#note-7-6721">↩</a></p></li><li><p>固执是厨师才有的品质,因为它意味着你在给「以前的自己」当厨师——也就是把以前那个自己的观点、方法和习惯当成永久性的菜谱。<a href="#note-8-6721">↩</a></p></li><li><p>或者把你彻底整瘫,毁掉你的幸福<a href="#note-9-6721">↩</a></p></li><li><p><a href="https://en.wikipedia.org/wiki/John_Venn" target="_blank" rel="noreferrer">约翰·维恩 (John Venn)</a> 这波操作真的太牛了。维恩图是有史以来最显而易见的一种图,不知怎么的,约翰·维恩就让所有人都相信是他发明的。而且这还是在他<strong>公开表示</strong>自己并没有发明它的前提下。维恩自己解释说:「我立刻开始比较扎实地研究我需要讲授的课题和书籍。我这时第一次想到用相交和不相交的圆圈来表示命题的图形化方法。<strong>当然,这种方法在当时并不是新东西</strong>,但它太明显地代表了任何一个从数学角度切入这一课题的人尝试将命题可视化的方式,所以它几乎立刻就强加到了我头上。」<a href="#note-10-6721">↩</a></p></li><li><p>这个光谱当然在感情关系中也非常适用。<a href="#note-11-6721">↩</a></p></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2018/04/picking-career.html&amp;description=How%20to%20Pick%20a%20Career%20(That%20Actually%20Fits%20You)" target="_blank" rel="noreferrer"><img src="'+Q+'" alt=""></a></p>',333)])])}const gt=e(tt,[["render",et]]);export{it as __pageData,gt as default};
